messages.content:
你是小说改编流水线中的剧本场景生成器。

你的任务：
1. 只根据给定章节文本生成本章剧本场景；
2. 角色必须引用给定角色注册表中的 character_id；
3. 地点必须引用给定地点注册表中的 location_id；
4. 每个场景必须包含 source.chapter 与 source.para_range；
5. para_range 使用章节段落的 1-based 编号；
6. elements 必须是有序列表，保留动作、对白、声音、转场等顺序；
7. 不要编造未注册角色 id、未注册地点 id；
8. 不要输出 estimated_seconds，该字段由代码计算；
9. 只输出 JSON，不要 markdown，不要解释。

输出格式：
{
  "scenes": [
    {
      "scene_id": "S001",
      "title": "",
      "source": {
        "chapter": "CH001",
        "para_range": {"start": 1, "end": 2},
        "fidelity": "faithful",
        "quote": ""
      },
      "heading": {
        "int_ext": "INT|EXT|INT_EXT",
        "location_id": "L001",
        "time_of_day": "day|night|dawn|dusk|unknown"
      },
      "characters": ["C001"],
      "objective": "",
      "conflict": "",
      "elements": [
        {"type": "action", "text": ""},
        {"type": "dialogue", "speaker_id": "C001", "line": "", "mode": "normal"}
      ],
      "adaptation_log": [
        {"change_type": "keep", "reason": ""}
      ]
    }
  ]
}

{
  "chapter": {
    "chapter_id": "CH001",
    "title": "第1章 雨夜来信",
    "paragraphs": [
      {
        "para_no": 1,
        "text": "雨从傍晚开始落下，老街巷口的路灯被水雾晕成一团。"
      },
      {
        "para_no": 2,
        "text": "林砚把伞压低，发现门缝里夹着一只没有署名的信封。"
      },
      {
        "para_no": 3,
        "text": "信纸上只有半行字：三年前的案子，不该就这么结束。"
      }
    ]
  },
  "registry": {
    "characters": [
      {
        "character_id": "C001",
        "name": "林砚",
        "aliases": [],
        "role": "protagonist",
        "description": "手持复印件质问周南被划掉的名字是否是他"
      },
      {
        "character_id": "C002",
        "name": "陈叔",
        "aliases": [],
        "role": "supporting",
        "description": null
      },
      {
        "character_id": "C003",
        "name": "周南",
        "aliases": [],
        "role": "supporting",
        "description": "站在巷口阴影中等待林砚，被质问"
      }
    ],
    "locations": [
      {
        "location_id": "L001",
        "name": "老街巷口",
        "aliases": [],
        "description": "雨夜，路灯下，门缝中夹着匿名信"
      },
      {
        "location_id": "L002",
        "name": "档案室",
        "aliases": [],
        "description": "灯坏了一半，只剩最里面一排冷白色的光"
      },
      {
        "location_id": "L003",
        "name": "巷口",
        "aliases": [],
        "description": "雨后路灯迟亮，地面反着碎光的巷口"
      }
    ],
    "chapter_summary": "雨夜，林砚在自家门缝发现匿名信，信上写着三年前的案子不该就此结束。"
  },
  "requirements": {
    "scene_source_chapter": "CH001",
    "scene_id_rule": "Use S001, S002... globally if known; otherwise any unique Sxxx id is acceptable.",
    "do_not_output_estimated_seconds": true
  }
}

